import Vue from 'vue'
import Router from 'vue-router'
import HelloWorld from '@/components/HelloWorld'
import Page from '@/components/pages/page'
import Day1 from '@/components/pages/day1'
import Day2 from '@/components/pages/day2'
import Day3 from '@/components/pages/day3'
import Day4 from '@/components/pages/day4'
import Day5 from '@/components/pages/day5'
import Day6 from '@/components/pages/day6'
import Day7 from '@/components/pages/day7'
import Day8 from '@/components/pages/day8'
import Day9 from '@/components/pages/day9'
import Day10 from '@/components/pages/day10'
import Menu from '@/components/pages/menu'

Vue.use(Router)

export default new Router({
  routes: [
    {
      path: '/index',
      name: '首頁',
      component: HelloWorld
    },
    {
      path: '/page',
      name: '分頁',
      // component: Page,
      components: {
        default: Page,
        menupage: Menu
      },
      children: [
        {path: 'day1', name: '練習1', component: Day1},
        {path: 'day2', name: '練習2', component: Day2},
        {path: 'day3', name: '練習3', component: Day3},
        {path: 'day4', name: '練習4', component: Day4},
        {path: 'day5', name: '練習5', component: Day5},
        {path: 'day6', name: '練習6', component: Day6},
        {path: 'day7', name: '練習7', component: Day7},
        {path: 'day8', name: '練習8', component: Day8},
        {path: 'day9', name: '練習9', component: Day9},
        {path: 'day10', name: '練習10', component: Day10}
      ]
    }
  ]
})



