<template>
  <div>
    <div class="card">
      <h2>練習一</h2>
      <table>
          <tr>
              <td width="45%" align="left">
                  <p>姓名：<input type="text" v-model="name"></p>
                  <p>年齡：<input type="text" v-model="age"></p>
                  <p>性別：<input type="radio" id="gender1" v-model="gender" value="male"><label for="gender1">男</label>
                          <input type="radio" id="gender2" v-model="gender" value="female"><label for="gender2">女</label></p>
                  <p>興趣：<span v-for="(hbitem, hbIdx) in habbits" :key="hbIdx">
                              <input type="checkbox" :id="hbIdx" v-model="getHabbit" :value="hbitem"><label :for="hbIdx">{{ hbitem }}</label>&nbsp;
                          </span>
                  </p>
                  <p>喜愛顏色：<input type="text" v-model="likeColor" placeholder="請輸入色碼"></p>
              </td>
              <td width="10%"></td>
              <td width="45%" align="left">
                  <p>姓名：{{ name }}</p>
                  <p>年齡：{{ age }} <span v-if="age">歲</span></p>
                  <p>性別：{{ getGender }}</p>
                  <p>興趣：<span v-for="getHB in getHabbit" :key="getHB">{{ getHB }} </span></p>
                  <p>喜愛顏色：<span class="box" :style="{'backgroundColor': likeColor}"></span></p>
              </td>
          </tr>
      </table>
    </div>
    <div class="card">
      <h2>練習二</h2>
      <p>我有多少錢：<input type="text" v-model="money"></p>
      <table border="1" width="50%">
          <tr>
              <td>幣別</td>
              <td>幣值</td>
              <td>換算後</td>
          </tr>
          <tr v-for="(cItem, cIdx) in getMoney" :key="cIdx">
              <td>{{ cItem.cuno }}</td>
              <td>{{ cItem.rava }}</td>
              <td>{{ cItem.newMoney }}</td>
          </tr>
      </table>
    </div>
  </div>
</template>

<script>
export default {
  name: 'day3',
  data () {
    return {
      name: '',
      age: '',
      gender: '',
      getHabbit: [],
      likeColor: '',
      habbits: {'hb1': '打球', 'hb2': '看電影', 'hb3': '閱讀', 'hb4': '聽音樂', 'hb5': '看動漫', 'hb6': '寫程式', 'hb7': '追劇', 'hb8': '躺著不動'},
      money: '',
      ravaList: [
        {'cuno': '美金(USD)', 'rava': '29.885', 'newMoney': 0},
        {'cuno': '港幣(HKD)', 'rava': '3.869', 'newMoney': 0},
        {'cuno': '英鎊(GBP)', 'rava': '38.04', 'newMoney': 0},
        {'cuno': '韓元(KRW)', 'rava': '0.0265', 'newMoney': 0},
        {'cuno': '日圓(JPY)', 'rava': '0.281', 'newMoney': 0}]
    }
  },
  computed: {
    getGender: function () {
      var vm = this
      if (vm.gender === 'male') {
        return '男'
      } else if (vm.gender === 'female') {
        return '女'
      } else {
        return ''
      }
    },
    getMoney: function () {
      var vm = this
      var newMoneyArr = vm.ravaList
      for (var xKey in newMoneyArr) {
        let newMoney = vm.money * newMoneyArr[xKey]['rava']
        newMoneyArr[xKey]['newMoney'] = newMoney.toFixed(2)
      }
      return newMoneyArr
    }
  },
  created () {
    // console.log(this.$route.params.id)
    // const id = this.$route.params.id
    // this.$http.get(`https://randomuser.me/api/?seed=${id}`).then((response) => {
    //   console.log(response)
    // })
  }
}
</script>

<style>
.box {    /* 正方形 */
  display: inline-block;
  width: 2rem;
  height: 2rem;
  background-color: #FFFFFF;
  border: 1px solid;
  vertical-align: bottom;
}
</style>



