<template>
  <div>
    <div class="card">
      <h2>練習一－過渡CSS</h2>
      <input type="button" value="click me" @click="show = !show">
      <!--transition 只能放一個元素-->
      <transition name="fade"
        @before-enter="beforeEnter"
        @enter="enter"
        @after-enter="afterEnter"
        @enter-cancelled="enterCancelled"
        @before-leave="beforeLeave"
        @leave="leave"
        @after-leave="afterLeave"
        @leave-cancelled="leaveCancelled">
        <h3 class="title" v-show="show">哈囉</h3>
      </transition>
      <input type="button" value="click me" @click="changeView">
      <transition name="component-fade" mode="out-in">
        <component :is="view"></component>
      </transition>
      <!--transition-group 要給 key 可以放多個元素-->
      <transition-group name="fade" mode="out-in">
        <h3 class="title" v-show="show" key="A">哈囉</h3>
        <component :is="view" key="B"></component>
      </transition-group>
    </div>
    <!--animation-->
    <transition
      type="transition"
      name="fadeSec"
      appear
      enter-active-class="animated swing fadeSec-enter-active"
      leave-active-class="animated shake fadeSec-leave-active"
      appear-active-class="animated swing">
      <div v-if="showSec">哈囉你好嗎</div>
    </transition>
    <input type="button" value="點擊我" @click="hadleClick">
    <div>
      <!--使用@keyframes-->
      <input type="button" value="keyframes click me" @click="showThr = !showThr">
      <transition name="fadeThr">
        <div v-if="showThr">keyframes 你好嗎</div>
      </transition>
    </div>
  </div>
</template>

<script>
export default {
  name: 'day10',
  data () {
    return {
      show: true,
      showSec: true,
      showThr: true,
      view: 'v-a'
    }
  },
  components: {
    'v-a': {
      template: '<div>元件aa</div>'
    },
    'v-b': {
      template: '<div>元件bb</div>'
    }
  },
  methods: {
    hadleClick () {
      var vm = this
      vm.showSec = !vm.showSec
    },
    changeView () {
      if (this.view === 'v-a') {
        this.view = 'v-b'
      } else {
        this.view = 'v-a'
      }
    },
    beforeEnter: function (el) {
      console.log('beforeEnter')
    },
    enter: function (el, done) {
      console.log('enter')
    },
    afterEnter: function (el) {
      console.log('afterEnter')
    },
    enterCancelled: function (el) {
      console.log('enterCancelled')
    },
    beforeLeave: function (el) {
      console.log('beforeLeave')
    },
    leave: function (el, done) {
      console.log('leave')
    },
    afterLeave: function (el) {
      console.log('afterLeave')
    },
    leaveCancelled: function (el) {
      console.log('leaveCancelled')
    }
  }
}
</script>

<style>
@keyframes bounce-in {
  0% {
    transform: scale(0);
  }
  50% {
    transform: scale(1.5);
  }
  100% {
    transform: scale(1);
  }
}
.fadeThr-enter-active {
  transform-origin: right center;
  animation: bounce-in 1s;
}
.fadeThr-leave-active {
  transform-origin: left center;
  animation: bounce-in 1s reverse;
}
.title {
  width: 100px;
  line-height: 26px;
  font-size: 16px;
  color: blue;
}
/** name-執行動作*/
.fade-enter, .fade-leave-to, .component-fade-enter, .component-fade-leave-to, .fadeSec-enter, .fadeSec-leave-to {
  opacity: 0;
}
.fade-enter-active, .fade-leave-active, .fadeSec-enter-active, .fadeSec-leave-active {
  transition: opacity .2s ease-in-out;
}
.component-fade-enter-active, .component-fade-leave-active {
  transition: opacity .3s ease;
}
</style>



