<template>
  <div>
    <div class="card">
      <h2>練習一</h2>
      <table>
        <tr>
          <td width="30%">
            <p>距離吃午餐倒數：<input type="text" size="3" v-model="lunchTime" v-on:change="countTime">分鐘</p>
            <h1 style="font-style:italic;">倒數 {{ lastTime }} 秒</h1>
          </td>
          <td width="5%"></td>
          <td width="30%">
            <p>距離下班倒數：<input type="text" size="3" v-model="offWorkTime" v-on:change="countTime2">分鐘</p>
              <h1 style="font-style:italic;">倒數 {{ lastTime2 }} 秒</h1>
          </td>
          <td width="5%"></td>
          <td width="30%">
            <p>距離睡覺倒數：<input type="text" size="3" v-model="sleepTime">秒鐘</p>
            <h1 style="font-style:italic;">倒數 {{ lastTime3 }} 秒</h1>
          </td>
        </tr>
      </table>
    </div>
    <div class="card">
      <h2>練習二</h2>
      <p>目前div數有：<input type="text" size="3" v-model.number="divCount"> 個</p>
      <div id="divClass" v-if="divCount > 0">
        <div class="divBoxClass" v-for="divIdx in divCount" :key="divIdx">div {{ divIdx }}</div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'day4',
  data () {
    return {
      timer: '',
      timer2: '',
      lunchTime: '',
      offWorkTime: '',
      sleepTime: 0,
      lastTime: '',
      lastTime2: '',
      lastTime3: 0,
      divCount: ''
    }
  },
  watch: {
    sleepTime: function () {
      console.log('sleepTime')
      var vm = this
      vm.lastTime3 = vm.sleepTime
      clearInterval(vm.Interval)
      this.countTime3()
    }
  },
  methods: {
    countTime () {
      var vm = this
      // 判斷是否還在計時,如有停掉原本的重新計時
      if (vm.timer) {
        clearInterval(vm.timer)
      }
      var getMins = parseInt(vm.lunchTime)
      vm.lastTime = 60 * getMins
      if (vm.lunchTime) {
        vm.timer = setInterval(function () {
          vm.lastTime--
          if (vm.lastTime === 0) {
            clearInterval(vm.timer)
            vm.timer = ''
          }
        }, 1000)
      }
    },
    countTime2 () {
      var vm = this
      // 判斷是否還在計時,如有停掉原本的重新計時
      if (vm.timer2) {
        clearInterval(vm.timer2)
      }
      var getMins = parseInt(vm.offWorkTime)
      vm.lastTime2 = 60 * getMins
      if (vm.offWorkTime) {
        vm.timer2 = setInterval(function () {
          vm.lastTime2--
          if (vm.lastTime2 === 0) {
            clearInterval(vm.timer2)
            vm.timer2 = ''
          }
        }, 1000)
      }
    },
    countTime3 () {
      var vm = this
      // 箭頭函式的this固定式最外層的
      // function () 的this是不固定的,所以需指定,clearInterval才可以清空對的Interval
      // this.Interval = setInterval(() => {
      vm.Interval = setInterval(function () {
        vm.lastTime3--
        if (vm.lastTime3 === 0) {
          // clearInterval(this).Interval)
          clearInterval(vm.Interval)
          vm.lastTime3 = ''
        }
      }, 1000)
    }
  }
}
</script>

<style>
#divClass {
  border-width:2px;
  border-style:solid;
  border-color:gold;
  padding:2px;
  width:800px;
  display:flex;
  flex-wrap:wrap;
  justify-content:flex-start;
}
.divBoxClass {
  border-width:5px;
  border-style:solid;
  border-color:#FFFFFF;
  background-color:gold;
  padding:2px;
  width:18%;
}
</style>



