<template>
  <div>
    <div class="card" style="width:800px;">
      <h2>練習一</h2>
      <div>
        <div style="height:50px;">
          <input type="button" class="menuBtnClass" v-for="(menuItm, menuIdx) in menuType" :value="menuItm.name" :key="menuIdx" @click="changeMenuTitle(menuItm)">
        </div>
        <div>
          <panda-component :panda-title="menuTitle" :panda-rice="rice" :panda-noodles="noodles" :panda-soup="soup" :panda-beverage="beverage"></panda-component>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'day7',
  data () {
    return {
      menuTitle: '',
      menuType: [
        {'type': 'rice', 'name': '飯類/rice'},
        {'type': 'noodles', 'name': '麵類/noodles'},
        {'type': 'soup', 'name': '湯類/soup'},
        {'type': 'beverage', 'name': '飲料/beverage'}],
      rice: [
        {name: '滷肉飯', price: 35},
        {name: '雞肉飯', price: 30},
        {name: '鴨肉飯', price: 30},
        {name: '燒肉飯', price: 45}],
      noodles: [
        {name: '乾麵', price: 35},
        {name: '麻醬麵', price: 35},
        {name: '餛飩麵', price: 55},
        {name: '鍋燒烏龍麵', price: 75},
        {name: '鍋燒意麵', price: 75},
        {name: '榨菜肉絲麵', price: 50}],
      soup: [
        {name: '貢丸湯', price: 25},
        {name: '粉腸湯', price: 35},
        {name: '菜頭湯', price: 20},
        {name: '青菜豆腐湯', price: 30},
        {name: '油豆腐湯', price: 35},
        {name: '綜合湯', price: 50}],
      beverage: [
        {name: '可樂', price: 25},
        {name: '雪碧', price: 25},
        {name: '綠茶', price: 20},
        {name: '紅茶', price: 20}]
    }
  },
  components: {
    'panda-component': {
      props: ['pandaTitle', 'pandaRice', 'pandaNoodles', 'pandaSoup', 'pandaBeverage'],
      template: ` <div>
                      <div style="float:left;height:100px;" v-for="(eatItm, eatIdx) in getMemuList" :key="eatItm.name">
                          <div class="divPandaBoxClass">
                              <div>
                                  <div style="float:left;width:120px;">
                                      <p>{{ eatItm.name }}</p>
                                      <p>NT$ {{ eatItm.price }}</p>
                                  </div>
                                  <div style="float:left;">
                                      <input type="button" class="pandaBtnClass" value="+">
                                  </div>
                              </div>
                          </div>
                          <div style="width:30px;float:left;">&emsp;</div>
                      </div>
                  </div>
                  `,
      computed: {
        getMemuList: function () {
          var vm = this
          var newMenu = []
          if (vm.pandaTitle === 'rice') {
            newMenu = vm.pandaRice
          } else if (vm.pandaTitle === 'noodles') {
            newMenu = vm.pandaNoodles
          } else if (vm.pandaTitle === 'soup') {
            newMenu = vm.pandaSoup
          } else if (vm.pandaTitle === 'beverage') {
            newMenu = vm.pandaBeverage
          }
          return newMenu
        }
      }
    }
  },
  methods: {
    changeMenuTitle (itm) {
      this.menuTitle = itm.type
    }
  }
}
</script>

<style>
.menuBtnClass {
  font-size: 3vmin;
  font-family: 'Microsoft JhengHei';
  font-weight: bold;
  background-color: #FFFFFF;
  border: 0px solid #FFFFFF;
  cursor: pointer;
}
.menuBtnClass:hover, .menuBtnClass:focus {
  color:olivedrab;
}
.pandaBtnClass {
  color: #FFFFFF;
  background-color: rgb(214, 38, 132);
  border: 0px solid rgb(214, 38, 132);
  cursor: pointer;
  height: 20px;
  width: 20px;
  padding: 0px;
}
#divPandaClass {
  border-width:0px;
  border-style:solid;
  padding:2px;
  width:800px;
  display:flex;
  flex-wrap:wrap;
  justify-content:flex-start;
}
.divPandaBoxClass {
  box-shadow:2px 2px 5px 1px #c5c0c0;
  border-width:5px;
  border-style:solid;
  border-color:#FFFFFF;
  background-color:#FFFFFF;
  padding:2px;
  width:160px;
  float:left;
  text-align: left;
}
</style>



