<template>
  <div>
    <div class="card">
      <h2>練習一</h2>
      <!--仿（好丘）網站標題-->
      <div>
        <web-component :web-value="webItem" v-for="(webItem, webKey) in webList" :key="webKey" @clickweb="changeWebTitle"></web-component>
        <p>&emsp;&emsp;{{ webWord }}</p>
      </div>
    </div>
    <div class="card">
      <h2>練習二</h2>
      <!--仿（童綜合醫院網頁）網站標題-->
      <div>
        <hosp-component
          :hosp-value="hospItem"
          :hosp-key="hospIdx"
          :hosp-sub="hospSubList"
          v-for="(hospItem, hospIdx) in hospList" :key="hospItem">
        </hosp-component>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'day6',
  data () {
    return {
      webWord: '',
      webList: ['門市通路', '新品資訊', '貝果訂購', '在地選品', '環境友善', '活動展演'],
      hospList: {'0': '就醫指南', '1': '醫院簡介', '2': '衛教園地'},
      hospSubList: {
        '0': ['如何門診', '如何辦理住院'],
        '1': ['樓層簡介', '門診簡介'],
        '2': ['糖尿病衛教', '戒菸衛教', '減肥衛教']}
    }
  },
  components: {
    'web-component': {
      props: ['webValue'],
      template: `<input type="button" class="titleBtn" :value="webValue" @click="clickWebTitle">`,
      methods: {
        clickWebTitle () {
          // 內部傳值到外部需透過emit=>function
          // this.$emit('事件名稱' 要傳遞的參數);
          this.$emit('clickweb', this.webValue)
        }
      },
      data () {
        return {
          text: '局部註冊'
        }
      }
    },
    'hosp-component': {
      props: ['hospValue', 'hospKey', 'hospSub'],
      // 有2個根元素 input、ul，需用div包起來，否則會報錯
      template: `
      <div class="hosSubDiv" style="float:left;">
          <input type="button" class="titleBtn" :value="hospValue">
              <ul class="hospSubClass">
                  <li class="hospSubliClass" v-for="(hospBubItem) in hospSub[hospKey]"> {{ hospBubItem }}</li>
              </ul>
      </div>
      `
    }
  },
  methods: {
    changeWebTitle (val) {
      this.webWord = '目前頁面：' + val
    }
  }
}
</script>

<style>
.titleBtn {
  background-color: #FFFFFF;
  border: 0px solid #FFFFFF;
  cursor: pointer;
  width: 15vmin;
  font-size: 2vmin;
  font-family: 'Microsoft JhengHei';
}
.titleBtn:hover, .titleBtn:focus {
  color:darkgoldenrod;
}
.hosSubDiv {
  position: relative;
}
.hospSubClass {
  visibility: hidden;
}
.hosSubDiv:hover .hospSubClass {    /* hover 下拉式選單*/
  visibility: visible;
}
.hospSubliClass {
  list-style-type: none;
  cursor: pointer;
  text-align: left;
  margin-left: 30px;
}
.hospSubliClass:hover {
  color:darkgoldenrod;
}
</style>



